var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아버지의 이름, 추억, 기록…… 관련된 모든 것들이 사라졌어요.","JPN":"お父さんの名前、記憶、記録……関係するあらゆるものが消えてしまいました。","ENG":"His name, memories and records of him... everything about him just disappeared.","TWN":"有關爸爸的名字、記憶、紀錄……一切都蕩然無存。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이건 누군가 의도적으로 아버지의 기록을 지워버리지 않으면 있을 수 없는 일이죠.","JPN":"これはもう、何者かが意図を持って、そうしたとしか思えないんです。","ENG":"And this can't happen unless there is someone intentionally deleting my father's records.","TWN":"肯定是有人刻意將有關爸爸的紀錄都抹滅掉，否則怎麼可能。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그렇다면 왜, 아버지는 세상에 흔적도 없이 사라져야 했을까요?","JPN":"でも、だとしたら、いったいなぜお父さんは世界から存在を消されなければならなかったんでしょう。","ENG":"Then, why? Why does he have to disappear without a trace?","TWN":"那又是為什麼？為何爸爸必須完全消失在這個世界上呢？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저는 꼭 알아내고 싶어요. 아버지에게 무슨 일이 일어난 것인지.","JPN":"私は必ずその答えを見つけ出したい。お父さんに何があったのか。","ENG":"I want to find out what happened to him.","TWN":"我想要找出答案，爸爸到底發生過什麼事。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"모든 것이 의문투성이예요.","JPN":"まだ全てが疑問のままです。","ENG":"Everything is full of questions.","TWN":"這一切都令人想不透。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이제 저에게 남은 건 건네받은 기억이 없는 이 나침반뿐.","JPN":"私に残されているのは、受け取った記憶もないこの羅針盤だけ。","ENG":"Now, all that's left is this compass that I don't remember receiving.","TWN":"而我現在有的，就只有這個我不知道怎麼會在我身上的指南針。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그런 일을 겪었을 줄은 몰랐어.","JPN":"君にそんなことがあったなんて。","ENG":"I didn't know you were going through such stuff.","TWN":"沒想到你經歷過這種事。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"요즘은 일반적인 일이죠. 침식 재난으로 가족을 잃는 것 정도는.","JPN":"最近では珍しいことではありません。侵食災害によって家族を失うことぐらい。","ENG":"It's normal these days, you know. Losing your family to a Corruption Disaster.","TWN":"這在最近算是很常見吧，誰沒有因為侵蝕災難而失去家人過。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"하지만, 자신의 불행을 선뜻 이야기하는 건 쉬운 일이 아니지.","JPN":"だが、自分が経験した不幸な出来事を、人に話すことは容易なことではない。","ENG":"But it's not easy to start talking about your own misfortunes.","TWN":"但是可以侃侃而談自己的遭遇，這很不容易。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"한배를 탔으니, 저도 제 얘기를 해야 하지 않겠어요?","JPN":"同じ船に乗った仲ですから、自分のことをお話ししないと。","ENG":"We're in the same boat, so I should tell you my story, no?","TWN":"既然我們現在在同一條船上，那我也應該告訴你我的事嘛？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"허, 제발 부탁 좀 들어달라고 드러누웠던 사람은 누구더라.","JPN":"はは、頼みを聞いてほしいと、駄々をこねていた人の発言とは思えんな。","ENG":"Pfft. Weren't you on your knees begging me to listen?","TWN":"拜託，是誰死皮賴臉地拜託我聽一下的。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"윽. 저도 공과 사는 구분할 줄 알거든요? 그리고 언제 드러누웠다고 그래요?!","JPN":"くっ、それはそれ、これはこれです。あと、駄々なんてこねていません！！","ENG":"Ngh. I know how to keep my personal and professional lives separate! And when did I even kneel and beg?!","TWN":"呃，我才不是那種公私不分的人好嗎？而且我哪有死皮賴臉？！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>금일. 강력한 침식파를 동반한 모래폭풍이 몰아치고 있습니다. </color>","JPN":"<color=#ffd34c>本日、強力な侵食波を伴う、砂嵐が吹き荒れています。</color>","ENG":"<color=#ffd34c>Today, there is a sandstorm accompanied by strong Corruption rays around the city.</color>","TWN":"<color=#ffd34c>今日，挾帶強烈侵蝕波的沙塵暴來勢洶洶。 </color>"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>예전보다 더 강한 침식파를 동반하고 있으므로 모두 각별히 주의해 주시기를 바랍니다. </color>","JPN":"<color=#ffd34c>前回より、さらに強い侵食波が確認されているため、より一層の注意を心掛けてください。</color>","ENG":"<color=#ffd34c>Please be advised that this one is accompanied by stronger Corruption rays than before.</color>","TWN":"<color=#ffd34c>此次的侵蝕波規模更勝以往，請民眾千萬要留意。</color>"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>모든 시민분들은 이터니움 쉴드량을 확인하시고, 모든 문을 닫아 주십시오. </color>","JPN":"<color=#ffd34c>市民の皆様は、エタニウムシールドの量を今一度ご確認し、全ての扉を閉めてください。</color>","ENG":"<color=#ffd34c>We ask all citizens to check their Eternium shields, and close all doors.</color>","TWN":"<color=#ffd34c>同時請確認永恆之金護盾的數量，並緊閉大門。</color>"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>또한, 모래 폭풍의 영향으로 침식체가 활동을 시작하고 있어 외부 활동은 자제하시기 바랍니다. </color>","JPN":"<color=#ffd34c>また、砂嵐の影響により、侵食体が活動を開始しているため、外出などはお控えください。</color>","ENG":"<color=#ffd34c>Also, please refrain from outdoor activities as C.O.s will become active due to the effects of the sandstorm.</color>","TWN":"<color=#ffd34c>此外，受到沙塵暴的影響，侵蝕體開始蠢蠢欲動，請民眾減少外出機會。</color>"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BROADCAST_HAVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>상황이 악화하여 구조대를 보내지 못하고 있으니……. </color>","JPN":"<color=#ffd34c>現在、救助隊を送ることは困難な状況となっているため……</color>","ENG":"<color=#ffd34c>We will not be able to send a rescue team due to the worsened situation...</color>","TWN":"<color=#ffd34c>由於情況惡化，無法派遣救難隊……</color>"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"오늘따라 모래 폭풍이 더 심해졌네요.","JPN":"今日の砂嵐は、いつもより勢いが増しています。","ENG":"The sandstorm got worse today.","TWN":"今天沙塵暴好像特別嚴重。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"게다가, 이렇게 침식파가 섞여 있는 모래 폭풍은 20년 전에 딱 한 번 있었던 일이에요.","JPN":"それに、侵食波を伴う砂嵐は、20年前にあった以来です。","ENG":"Also, a sandstorm with Corruption rays only occurred once twenty years ago.","TWN":"像這種挾帶侵蝕波的沙塵暴，20年前才發生過一次而已。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"20년 전의…… 모래 폭풍…… 침식파…….","JPN":"20年前の……砂嵐……侵食波……","ENG":"Twenty years ago... Sandstorm... Corruption rays...","TWN":"20年前的……沙塵暴……侵蝕波……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그게 아니라면…… 헉, 설마……!","JPN":"それとも……はっ、まさか……！","ENG":"If that's not it... Then...!","TWN":"不是這樣的話……難道……！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"혹시 천년의 역사를 지닌 도시, 에리두를 삼켰다는 전설 속의 침식체?","JPN":"あの千年の歴史を持つ都市、エリドゥを飲み込んだといわれる、伝説の侵食体？","ENG":"Could it be the legendary C.O. that swallowed Eridu, the city with a thousand-year history?","TWN":"難道是傳說中的侵蝕體？據說它吞噬掉有著千年以上歷史的埃里都。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"전설 속의 침식체는 너무 거창한 거 아닌가?","JPN":"伝説の侵食体とは、大げさすぎないか？","ENG":"Don't you think \\"legendary C.O.\\" is overdoing it?","TWN":"傳說中的侵蝕體，這個說法會不會太誇大？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"에헤이. 워낙 유명한 이야기인데, 그것도 모르시는구나?!","JPN":"いやいや、もしかしてこの有名な話をご存知ないんですか！？","ENG":"Huh? It's a famous story! Don't you know it?","TWN":"嘿嘿～這個傳說很有名欸，你連這個也不知道喔？！"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"얼굴이 너무 가깝다.","JPN":"顔が近すぎるぞ。","ENG":"You're too close.","TWN":"臉不要靠這麼近。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};